&lt;div class=&quot;separator&quot; style=&quot;clear: both;&quot;&gt;&lt;a href=&quot;https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEiTd5nOc750JG4nYlbdEzsKUhBA3eWp5jBPGj-ie27fmiQGCy-OrwO9rW4-hACVvFejNOrXyVcgIc5-dY_UqmMxGih5Ku4ob63vkaV8ZCIgOLHR6sKzDWE_Xea15n-o0g6BTOG-sRtJxmYZ6VIFo4hu0Yco5ZXm-wAV4dA_UBBFMecpJtmkS3ItXft3w54/s2048/000004.xwd.png&quot; style=&quot;display: block; padding: 1em 0; text-align: center; &quot;&gt;&lt;img alt=&quot;&quot; border=&quot;0&quot; width=&quot;320&quot; data-original-height=&quot;1200&quot; data-original-width=&quot;2048&quot; src=&quot;https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEiTd5nOc750JG4nYlbdEzsKUhBA3eWp5jBPGj-ie27fmiQGCy-OrwO9rW4-hACVvFejNOrXyVcgIc5-dY_UqmMxGih5Ku4ob63vkaV8ZCIgOLHR6sKzDWE_Xea15n-o0g6BTOG-sRtJxmYZ6VIFo4hu0Yco5ZXm-wAV4dA_UBBFMecpJtmkS3ItXft3w54/s320/000004.xwd.png&quot;/&gt;&lt;/a&gt;&lt;/div&gt;

