  align-items: center;
}
.fourth-era-march .gui-traffic { display: flex; gap: 0.4em; }
.fourth-era-march .dot { width: 0.75em; height: 0.75em; border-radius: 50%; }
.fourth-era-march .d-red    { background: #ff5f57; }
.fourth-era-march .d-yellow { background: #febc2e; }
.fourth-era-march .d-green  { background: #28c840; }
.fourth-era-march .gui-title {
  grid-column: 2;
  font-size: 0.85em;
  font-weight: 600;
  color: #1d1d1f;
}
.fourth-era-march .gui-body { padding: 0.3em 0.9em 0.5em; }
.fourth-era-march .gui-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.5em 0;
  border-bottom: 1px solid #e3e3e6;
  font-size: 0.9em;
}
.fourth-era-march .gui-row:last-child { border-bottom: none; }
.fourth-era-march .gui-toggle {
  width: 1.9em;
  height: 1.1em;
  background: #d1d1d6;
  border-radius: 1em;
  position: relative;
  flex-shrink: 0;
}
.fourth-era-march .gui-toggle::after {
  content: &quot;&quot;;
  position: absolute;
  top: 0.1em;
  left: 0.1em;
  width: 0.9em;
  height: 0.9em;
  background: #fff;
  border-radius: 50%;
  box-shadow: 0 1px 2px rgba(0,0,0,0.2);
}
.fourth-era-march .gui-toggle.on { background: #34c759; }
.fourth-era-march .gui-toggle.on::after { left: auto; right: 0.1em; }
